			rownum as rnum, roomRental_no, roomRental_title, roomRental_date, roomRental_hits
		FROM roomRental 
		where  



	 rownum <= #{pageNum} * #{amount} AND user_id  = #{user_id} 
		) roomList
	WHERE rnum > (#{pageNum} - 1) * #{amount}

SELECT count(*) 
FROM roomRental
WHERE user_id  = #{user_id}

